class PhysicalBook:
    def __init__(self, title, late_days):
        self.title = title
        self.late_days = late_days

    def fee(self):
        return self.late_days * 2

class DVD:
    def __init__(self, title, late_days):
        self.title = title
        self.late_days = late_days

    def fee(self):
        return self.late_days * 3

